mapper.select:
SELECT ID, EQUIP_ID, CHANGE_TYPE, CASE CHANGE_TYPE WHEN 'BASIC_INFO' THEN '设备基本信息' WHEN 'FINANCE' THEN '财务信息' WHEN 'SUPPLY' THEN '供货信息' WHEN 'SPECIAL_INFO' THEN '特种设备信息' ELSE CHANGE_TYPE END AS CHANGE_TYPE_NAME, CHANGE_BY, CHANGE_BY_NAME, CHANGE_TIME FROM E_M_EQPT_CHANGE_LOG WHERE DEL_FLAG = 0
AND EQUIP_ID = #{equipId}
AND CHANGE_TYPE = #{changeType}
ORDER BY CHANGE_TIME DESC
